import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';
import App from './App';
import reportWebVitals from './reportWebVitals';
import * as serviceWorkerRegistration from './serviceWorkerRegistration';

import { BrowserRouter } from 'react-router-dom';

import { Provider } from 'react-redux';
import { combineReducers, createStore } from 'redux';

let alert초기값 = true;

function reducer2(state = alert초기값 , 액션) {
  if( 액션.type === '닫기눌림'){
    return false;
  }else {
    return state;
  }
}

let 초깃값 = [{ id : 0, name : '멋진신발' , quan : 2 },
                { id : 1, name : '못난신발' , quan : 3 },
                { id : 2, name : '이쁜신발' , quan : 4 }];
// let 초깃값 = [];
function reducer(state = 초깃값, 액션) {
  if (액션.type === '항목추가') {
    let 몇번째있니 = state.findIndex( (a)=>{ return a.id === 액션.payload.id } )
    if (몇번째있니 >= 0){
      console.log('으익')
      let copy = [...state];
      copy[몇번째있니].quan= Number(copy[몇번째있니].quan) + Number(액션.payload.quan);
      return copy
    }else{    
      console.log(액션.payload)
      let copy = [...state];
      copy.push(액션.payload)
      return copy
    }
  }else if (액션.type === '항목삭제'){
    let 몇번째있니 = state.findIndex( (a)=>{ return a.id === 액션.data } )
    if (몇번째있니 >= 0 ){
      let copy = [...state];
      // console.log(copy)
      copy.splice(몇번째있니, 1); // 삭제 
      return copy
    }
  }
  else if ( 액션.type === '수량증가' ) {
    let 몇번째있니 = state.findIndex( (a)=>{ return a.id === 액션.data } )
    if (몇번째있니 >= 0 ){
      let copy = [...state];
      copy[몇번째있니].quan++;
      return copy
    }
    
    return state

  } else if (액션.type === '수량감소'){
    let 몇번째있니 = state.findIndex( (a)=>{ return a.id === 액션.data } )
    if (몇번째있니 >= 0 ){
      let copy = [...state];
      if(copy[몇번째있니].quan === 1) return copy;
      copy[몇번째있니].quan--;
      return copy
    }
    return state
  }
  else {
    return state
  }
}

let store = createStore(combineReducers({reducer,reducer2}));
// let store = createStore(reducer);

ReactDOM.render(
  <React.StrictMode>
    <BrowserRouter>
      <Provider store = {store} >
        <App />
      </Provider> 
    </BrowserRouter>
  </React.StrictMode>,
  document.getElementById('root')
);

// If you want your app to work offline and load faster, you can change
// unregister() to register() below. Note this comes with some pitfalls.
