import React,{useEffect, memo} from 'react';
import { Table } from 'react-bootstrap';
import { connect } from 'react-redux';

function Cart(props){
    return (
      <div>
        <Table responsive>
          <tr>
            <th>#</th>
            <th>상품명</th>
            <th>수량</th>
            <th>변경</th>
            <th></th>
          </tr>
          {/* <tr>
            <td>1</td>
            <td>{props.으으윽[0].id}</td>
            <td>{props.으으윽[0].name}</td>
            <td>{props.으으윽[0].quan}</td>
          </tr> */}
          {
            props.으으윽.map(function(data,index){

                return(
                <tr ket = {index}>
                    <td>{data.id}</td>
                    <td>{data.name}</td>
                    <td>{data.quan}</td>
                    <td><button onClick={() => { props.dispatch( {type:'수량증가',data : data.id}  ) }}>+</button>
                        <button onClick={() => { props.dispatch( {type:'수량감소',data : data.id}  ) }}>-</button>
                    </td>
                    <td><button onClick={() => { props.dispatch( {type:'항목삭제',data : data.id}  ) }}>x</button></td>
                </tr>
                )
            })
          }
        </Table>
        { props.alert열렸니 === true ? 
        <div className = "my-alert2">
          <p>지금 구매하시면 신규할인 20%</p>
          <button onClick={() => { props.dispatch( {type:'닫기눌림' } ) }}>닫기</button>
        </div>
          : null
        }
        <Parent 이름 = "존박" 나이 = "20"/>
      </div>
    )
  }


function state를props화(state) {
  console.log(state)
    return{
        // 으윽 : state[0].name
        // 으으윽 : state['reducer']
        으으윽 : state.reducer,
        alert열렸니 : state['reducer2']
    }
}

function Parent(props){
  return (
    <div>
      <Child1 이름 = {props.이름}/>
      <Child2 나이 = {props.나이}/> 
    </div>
  )
}
function Child1(){
useEffect( ()=>{ console.log('렌더링됨1') } );
return <div>1111</div>
}
let Child2 = memo(function (){
useEffect( ()=>{ console.log('렌더링됨2') } );
return <div>2222</div>
})

export default connect(state를props화)(Cart)
